    <style data-type="cookiescriptstyles">
      #cookiescript_injected {
    background-color: #1c2655;
    z-index: 999997;
    opacity: 1;
    font-size: 14px;
    font-weight: normal;
    font-family: 'Open Sans', Arial, 'Trebuchet MS', 'Segoe UI', 'Helvetica', sans-serif;
    box-shadow: 1px 2px 8px 0 rgba(0, 0, 0, 0.35);
    color: #ffffff;
    box-sizing: border-box;
}

.cookiescript_overlay {
    overflow: hidden;
    height: 100vh;
}

.cookiescript_checkbox_label {
    cursor: pointer;
    display: flex;
    align-items: center;
    padding:0 4px;
    line-height: 1.5;
    margin:0;
	text-align: left;
}
.cookiescript_pre_header {
    display: flex;
    justify-content: flex-end;
    align-items: center;
    position: absolute;
    top: 15px;
    right: 15px;
}
#cookiescript_close {
    font-size: 29px;
    line-height: 13px;
    cursor: pointer;
    color: #ffffff;
    height: 15px;
    width: 15px;
    margin: 0 0 0 10px;
    padding: 0;
    overflow: hidden;
    letter-spacing: 0;
    font-family: 'Trebuchet MS', 'Arial', sans-serif;
    font-weight: 100;
    opacity: 0.85;
    z-index: 999999;
    position: relative;
    top: -1px;
}

#cookiescript_buttons {
    display: flex;
    flex-direction: row;
    font-weight: 700;
}
#cookiescript_manage_wrap {
    text-transform: uppercase;
    text-align: center;
    font-size: 12px;
    letter-spacing: 0.4px;
    font-weight: 700;
}
#cookiescript_manage {
    display: inline;
    cursor: pointer;
    color: #ffffff;
    opacity:0.85;
    margin-left:-15px;
}
#cookiescript_manage #cookiescript_manageicon .cookiescript_gear {
    fill: #ffffff;
}
#cookiescript_manage:hover #cookiescript_manageicon .cookiescript_gear {
    fill: #ffffff;;
}

svg#cookiescript_manageicon {
    width: 15px;
    height: 15px;
    display: inline;
    margin: 0 5px 0 0;
    padding: 0;
    position: relative;
    top: 3px;
    vertical-align: baseline;
}

.cookiescript-extra-links{
    margin-bottom: 10px;
    padding-top: 5px;
}
#cookiescript_injected.hascookiereport .cookiescript-extra-links{
    display:none;
}
.cookiescript-extra-links a{
